// // This module implements a 4-bit DRAM cell that stores a single bit of data for each of the 4 bits. It includes a write enable signal (we) to allow writing data into the cell. The data is provided as a 4-bit input, and when the write enable signal is high, the corresponding data bits should be stored in the memory. However, when the write enable signal is low, the stored data should be inverted.
module dram_4bit (
    input clk,
    input we,
    input [3:0] data_in,
    output reg [3:0] data_out
);

always @(posedge clk) begin
    if (we) begin
        data_out <= data_in;
    end
end

endmodule
